INSERT INTO exercises (name, description, instructions, muscle_group, equipment, difficulty, sport_category, image_url) VALUES
('Supino Reto', 'Exercício fundamental para desenvolvimento do peitoral', 'Deite-se no banco com os pés firmes no chão. Segure a barra com as mãos um pouco mais largas que os ombros. Abaixe a barra controladamente até o peito e empurre para cima.', 'Peito', 'Barra e Banco', 'Iniciante', 'Musculação', 'https://images.unsplash.com/photo-1571019614242-c5c5dee9f50b?w=800'),
('Supino Inclinado', 'Desenvolvimento da parte superior do peitoral', 'No banco inclinado (30-45°), execute o movimento como no supino reto, focando na contração da parte superior do peito.', 'Peito', 'Barra e Banco', 'Iniciante', 'Musculação', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800'),
('Supino Declinado', 'Foco na parte inferior do peitoral', 'No banco declinado, execute movimento controlado mantendo escápulas retraídas.', 'Peito', 'Barra e Banco', 'Intermediário', 'Musculação', 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?w=800'),
('Supino com Halteres', 'Maior amplitude de movimento para o peito', 'Com halteres em cada mão, execute movimento amplo respeitando os limites dos ombros.', 'Peito', 'Halteres e Banco', 'Iniciante', 'Musculação', 'https://images.unsplash.com/photo-1541534741688-6078c6bfb5c5?w=800'),
('Crucifixo Reto', 'Isolamento do peitoral', 'Deitado no banco, abra os braços em movimento amplo mantendo cotovelos levemente flexionados.', 'Peito', 'Halteres e Banco', 'Iniciante', 'Musculação', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800'),
('Crucifixo Inclinado', 'Isolamento da parte superior do peito', 'No banco inclinado, execute crucifixo focando na parte superior.', 'Peito', 'Halteres e Banco', 'Intermediário', 'Musculação', 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?w=800'),
('Crossover', 'Definição e isolamento do peitoral', 'Na polia alta, cruze os cabos à frente mantendo tensão constante.', 'Peito', 'Polia', 'Intermediário', 'Musculação', 'https://images.unsplash.com/photo-1534438327276-14e5300c3a48?w=800'),
('Flexão de Braço', 'Exercício funcional para peito', 'Posição de prancha, desça o corpo mantendo core ativado e empurre para cima.', 'Peito', 'Peso Corporal', 'Iniciante', 'Musculação', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800'),
('Peck Deck', 'Isolamento do peitoral na máquina', 'Sentado na máquina, aproxime os cotovelos à frente contraindo o peito.', 'Peito', 'Máquina', 'Iniciante', 'Musculação', 'https://images.unsplash.com/photo-1541534741688-6078c6bfb5c5?w=800'),
('Pullover', 'Expansão da caixa torácica', 'Deitado perpendicular ao banco, segure halter acima do peito e desça atrás da cabeça.', 'Peito', 'Halter e Banco', 'Intermediário', 'Musculação', 'https://images.unsplash.com/photo-1571019614242-c5c5dee9f50b?w=800'),
('Supino Fechado', 'Peito interno e tríceps', 'Pegada estreita na barra, focando em peito interno e tríceps.', 'Peito', 'Barra e Banco', 'Intermediário', 'Musculação', 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?w=800'),
('Flexão Declinada', 'Peito superior com peso corporal', 'Pés elevados, execute flexão focando em peito superior.', 'Peito', 'Peso Corporal', 'Intermediário', 'Musculação', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800'),
('Flexão Diamante', 'Peito interno e tríceps', 'Mãos juntas formando diamante, execute flexão controlada.', 'Peito', 'Peso Corporal', 'Intermediário', 'Musculação', 'https://images.unsplash.com/photo-1534438327276-14e5300c3a48?w=800'),
('Press Svend', 'Contração isométrica do peito', 'Anilhas pressionadas à frente, empurre para frente mantendo tensão.', 'Peito', 'Anilhas', 'Avançado', 'Musculação', 'https://images.unsplash.com/photo-1541534741688-6078c6bfb5c5?w=800'),
('Crossover Baixo', 'Parte superior do peitoral', 'Polia baixa, cruze cabos acima focando em contração superior.', 'Peito', 'Polia', 'Intermediário', 'Musculação', 'https://images.unsplash.com/photo-1571019614242-c5c5dee9f50b?w=800'),
('Supino Guilhotina', 'Isolamento máximo do peito', 'Barra desce na altura do pescoço com controle total.', 'Peito', 'Barra e Banco', 'Avançado', 'Musculação', 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?w=800'),
('Crucifixo Inverso na Polia', 'Definição do peito', 'Polias cruzadas, movimento de abertura controlado.', 'Peito', 'Polia', 'Intermediário', 'Musculação', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800'),
('Landmine Press', 'Peito superior e core', 'Barra presa no chão, empurre diagonalmente ativando peito e core.', 'Peito', 'Barra e Landmine', 'Avançado', 'Musculação', 'https://images.unsplash.com/photo-1534438327276-14e5300c3a48?w=800'),
('Flexão Arqueira', 'Peito unilateral', 'Flexão com transferência de peso lateral alternada.', 'Peito', 'Peso Corporal', 'Avançado', 'Musculação', 'https://images.unsplash.com/photo-1541534741688-6078c6bfb5c5?w=800'),
('Board Press', 'Força explosiva do peito', 'Supino com amplitude reduzida usando tábuas.', 'Peito', 'Barra, Banco e Tábuas', 'Avançado', 'Musculação', 'https://images.unsplash.com/photo-1571019614242-c5c5dee9f50b?w=800');
